var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"이렇게 뵙게 되어 반갑습니다, 스펜서 씨.","JPN":"はじめまして、お会いできて光栄です、スペンサーさん。","ENG":"Pleased to meet you, Ms. Spencer.","TWN":"很高興認識你，史賓瑟女士。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"의외네. 나한테 의뢰를 맡기고 싶어하는 게 관리국인 줄은 몰랐는데.","JPN":"意外ね。依頼主がまさか管理局だったとは。","ENG":"Huh. I didn't expect the Administration to have a job for me.","TWN":"真是意外。沒想到是管理局委託我辦事。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"리프터의 직업수명은 짧아요. 당신만큼 수없이 대균열을 오가며 식견을 쌓은 프로는 더더욱 드물죠.","JPN":"ただでさえリフターの現役期間は短い。あなたほどの大亀裂に出入りした経験が豊富なベテランとなると、さらに限られる。","ENG":"Lifters have short lifespans. And professionals who have extensive experience traveling the Grand Dimension Crevice like you are even rarer.","TWN":"打撈人這行的職業生涯都十分短暫。像你這樣，多次來回大峽谷，經驗豐富的打撈人，更是少之又少。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"관리국의 예절과 관용은 남다르네. 우리 같은 한탕주의자를 무려 직업으로 취급해 주다니.","JPN":"管理局は相変わらず律儀で懐が深いな。私たちみたいな一攫千金狙いを正当に認めてくれるなんて。","ENG":"You Administration folks have great tolerance. Treating us gamblers like real professionals.","TWN":"管理局的禮儀和格局真是非同一般啊。居然把我們這樣的投機分子，也當作正經八百的職業來看待。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"챔버에선 기술력이 곧 지위입니다. 지위가 있으면 그에 합당한 대우를 받는 게 당연하죠.","JPN":"チェンバーは実力主義なんです。実力があればそれ相応の地位と待遇を受けるのは当然のことです。","ENG":"In Chamber, skill equates to status. And if you have status, it's only natural to receive treatment accordingly.","TWN":"在強巴，技術就是地位。有了地位，自然會得到應有的待遇。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"그게 설령 불법 다이브를 일삼는 범죄자라 해도, 논외는 아닙니다.","JPN":"たとえ違法ダイブを平然と繰り返す犯罪者であってもです。","ENG":"Even if that person is someone who engages in illegal dives, it won't be an issue.","TWN":"即使是非法躍入的犯罪分子，也不例外。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"단도직입적으로 묻지.","JPN":"単刀直入に聞く。","ENG":"I’ll cut to the chase.","TWN":"那我也不廢話了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"원하는 게 뭐야?","JPN":"何を望んでいる？","ENG":"What do you want?","TWN":"你們想要什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"3개월 전, 누군가 챔버 대균열 심층에 진입했습니다. 리프터들 사이에선 <color=#ffd34c>5층</color>이라 불리는 곳이죠.","JPN":"3カ月前、何者かによるチェンバー大亀裂の深層部への侵入がありました。リフターの間では<color=#ffd34c>5階</color>と呼ばれる場所です。","ENG":"Three months ago, someone infiltrated the depths of Chamber's Grand Dimension Crevice. Lifters call it the <color=#ffd34c>5th floor</color>.","TWN":"三個月前，有人進入了強巴大峽谷深處。那個被打撈人稱為<color=#ffd34c>地下5層</color>的地方。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"스펜서, 당신이 그곳에 들어간 침입자를 찾아줬으면 해요.","JPN":"スペンサーさん、あなたにはその侵入者を見つけていただきたい。","ENG":"Ms. Spencer, we want you to find the intruder who entered that place.","TWN":"史賓瑟女士，我們需要你找到闖入那裡的入侵者。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침입자?","JPN":"侵入者？","ENG":"Intruder?","TWN":"入侵者？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당신들이 말하는 침입자는 우리 같은 리프터와 뭐가 다르길래 현상금까지 걸지?","JPN":"その侵入者に懸賞金までかけるなんて、私たちリフターとは何が違うんだ？","ENG":"And how is this intruder so different from us lifters that you need to put out a bounty?","TWN":"你說的這些入侵者和我們這樣的打撈人有什麼不同，還要懸賞他們？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"알고 계시겠지만 이면세계의 아티팩트를 현실로 반출하는 건 불법입니다. 아티팩트의 존재가 현실에 끼치는 악영향 때문이죠.","JPN":"ご存知だと思いますが、裏世界のアーティファクトを現実に持ち出すのは違法行為です。アーティファクトが現実世界に及ぼす悪影響を懸念してのものなんです。","ENG":"As you may be aware, bringing Artifacts from the Counterside to the Normalside is illegal because the Artifacts can cause harmful effects to the Normalside.","TWN":"如你所知，將異界的人造神器帶入現實是違法的。這是因為人造神器的存在對現實造成了負面影響。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"그 침입자가 노리고 있는 아티팩트의 규격은 다른 케이스와 급이 달라요. 그걸 현실로 가져오는 순간 돌이킬 수 없게 될 겁니다.","JPN":"その侵入者が手に入れようとしているアーティファクトは、他のものとは格が違います。もしそれが現実世界に持ち込まれたら、取り返しのつかないことになってしまうでしょう。","ENG":"The specs of the Artifact that the intruder is targeting are on another level. Once brought into the Normalside, it will be irreversible.","TWN":"入侵者盯上的人造神器之規格遠超普通水準。一旦將其帶入現實，就沒有挽回的餘地了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"적어도 당신들은 5층에 그런 위험한 아티팩트가 있다는 걸 알고 있었단 거네.","JPN":"つまり、少なくともあなたちはそんな危険なアーティファクトが5階に眠っているということを知っていたということだな。","ENG":"So the Administration knew that a dangerous Artifact like that existed on the 5th floor, eh?","TWN":"最起碼你們知道地下五層有那種危險的人造神器。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"대정화전쟁 이후, 챔버 대균열은 이면세계를 개척하려는 기업들의 탐사가 가장 활발했던 곳입니다.","JPN":"大浄化戦争の終戦後、チェンバー大亀裂は裏世界の開拓を目指す企業たちによる探査が最も盛んに行われていた場所です。","ENG":"After the Great Purification War, the Chamber's Grand Dimension Crevice was the most active place for corporations trying to map out the Counterside.","TWN":"淨化之戰後，強巴的大峽谷是各勢力探索異界最為活躍的地方。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"기업이 가진 정보는 모두 관리국에게도 공유되고 있으니까요.","JPN":"企業の持つ情報は、全て管理局にも共有されていますからね。","ENG":"And all information held by corporations is also shared with the Administration.","TWN":"而公司持有的所有資訊也與管理局共用。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침입자가 5층으로 향한 게 3개월 전이라면 진작에 죽었어.","JPN":"その侵入者が5階に向かってから、もう3カ月も経っているなら間違いなく死んでいる。","ENG":"If this intruder headed to the 5th floor three months ago, he's long dead by now.","TWN":"如果入侵者三個月前去了地下五層，那他早就死了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"살아있을 겁니다. 그자가 무사히 그 아티팩트를 손에 넣었다면 말이죠.","JPN":"いいえ、生きています。もしその者が、問題なく例のアーティファクトを手に入れたのなら。","ENG":"He'll be alive. If he managed to obtain the Artifact he was looking for, that is.","TWN":"他們可能還活著。如果順利地拿到人造神器的話。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그건 또 무슨 소리지? 아티팩트가 무슨 부활장치라도 되나?","JPN":"それはいったいどういうことだ？　アーティファクトが復活装置にでもなるってことか？","ENG":"What does that mean? Is this Artifact some kind of resurrection device?","TWN":"這是什麼意思？人造神器是某種復活裝置嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"죄송합니다. 이 이상은 관리국 기밀사항이라서요.","JPN":"申し訳ございません。これ以上は管理局の機密事項になります。","ENG":"I apologize. Anything beyond this is classified information.","TWN":"對不起。這是管理局的機密資訊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"이건 관리국과의 협업을 비밀로 한다는 계약서와 저희가 제공하는 선수금입니다.","JPN":"これは管理局との協業と他言厳禁を条件とする契約書と前払い金です。","ENG":"This is a contract stating that you will be keeping your involvement with the Administration confidential, along with the advance payment for this request.","TWN":"這是與管理局合作的保密協定，以及我們預付的費用。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이 정도면 목숨이랑 맞바꿀만한 금액이네.","JPN":"確かに、これだけの金額なら命以上の価値があるな。","ENG":"This is enough money to trade my life in for.","TWN":"這筆錢夠買我幾條命了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나보다 앞서간 양반들도 남부럽지 않게 챙겼겠어.","JPN":"先に依頼した者たちにも、相当な額を支払っているのだろう？","ENG":"Were the poor saps who went ahead of me paid this handsomely as well?","TWN":"那些在我之前的人也能拿這麼多嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"그들은 당신에게 제시한 선수금의 반의 반도 미치지 않는 금액에 의뢰를 승낙했습니다.","JPN":"彼らはあなたへの前払い金の2割以下で承諾してくださっています。","ENG":"They accepted the job at a fraction of the amount we're offering you.","TWN":"他們的報酬不到你預付費用的一半。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"관리국이 당신에게 걸고 있는 기대는 차원이 다르거든요.","JPN":"管理局はあなたにそれだけ大きな期待をかけているのですよ。","ENG":"The expectations the Administration is placing on you are on a different level.","TWN":"管理局對你十分期待。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"음지에서 활동하는 날 관리국에서 인정하고 계시다니, 그것 참 영광이긴 한데.","JPN":"社会の暗部で働く私を管理局が認めていたなんて、それは光栄だけど。","ENG":"It's an honor for someone working in my line of work to be recognized by the Administration.","TWN":"呵呵，走在暗處的我能得到管理局的認可，真是一種榮幸。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"내가 필요한 건 정보야. 당신들이 찾는 침입자에 대한 정보 말이야.","JPN":"私には情報が必要だ。あなたたちが探し出そうとしている侵入者が誰なのか。","ENG":"But, what I need is information. Information on the intruder you're looking for.","TWN":"不過，我還需要一些情報。關於你們正在尋找的入侵者的資訊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"사람이 없어야 할 통제구역에 들어간 침입자를 찾는 일입니다. 정체가 누구인진 중요하지 않죠.","JPN":"人が入ってはいけない禁止区域での侵入者探しです。それが誰なのかは重要ではないはずでは。","ENG":"This is about finding the intruder who entered a restricted area. His identity isn't important.","TWN":"你的任務是找到進入管制區域的入侵者。那個人的真實身份並不重要。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"살아있는 사람이든, 죽은 시체든, 찾아낼 때마다 추가보수도 드릴 겁니다.","JPN":"生きている者であろうと、死体であろうとも見つけるごとに追加報酬も出します。","ENG":"You will be awarded additional compensation when you find living people or dead bodies.","TWN":"我們還會為你的每一次發現提供額外獎勵，無論是活人還是屍體。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"돈 문제가 아니야. 난 당신이 찾는 타깃에 대한 정보가 필요한 거니까.","JPN":"報酬の問題じゃない。私はそのターゲットについて知りたいだけだ。","ENG":"It's not about the money. I need information about the target you're looking for.","TWN":"這不是錢的問題。我需要有關你們正在尋找的目標的資訊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"제가 전달해 드릴 내용은 이게 전부예요.","JPN":"私からお伝えできる内容はここまでです。","ENG":"This is all the information I have for you.","TWN":"很抱歉，目前為止的就是我能透露給你的全部。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"계약서를 확인해보면 아시겠지만, 그 이상은 관리국 기밀사항이라…","JPN":"契約書にも記載してありますが、これ以上は管理局の機密事項となりますので……","ENG":"As you can see on the contract, anything beyond this is classified information...","TWN":"你只要檢查一下合約，就能發現超出這個範圍的事項都是管理局的機密……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그럼 돌아가. 의뢰는 없던 걸로 하지.","JPN":"そう、じゃあ帰って。依頼の話はなかったことにしよう。","ENG":"Then, take this back and get out of here. Forget we ever had this conversation.","TWN":"那你回去吧。就當沒有這次委託。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"네? 그럴 수가…!","JPN":"えっ？　ど、どうして……！","ENG":"What? You can't–!","TWN":"嗯？怎麼可以這樣……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"아, 잠시만요.","JPN":"あ、ちょっとお待ちください。","ENG":"Oh, excuse me.","TWN":"啊，等一下。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"예… 예.","JPN":"はい……はい。","ENG":"Yes... Yes.","TWN":"是……是。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"그렇습니까?","JPN":"そうなのですか？","ENG":"Is that so?","TWN":"這樣嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"알겠습니다. 그럼 그렇게 전달하겠습니다.","JPN":"わかりました。ではその通りに伝えておきます。","ENG":"Yes. I'll tell her that.","TWN":"好的。那我就這麼傳達給她。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"스펜서 씨. 전화 받아 보시죠.","JPN":"スペンサーさん。お電話代わっていただけますか。","ENG":"Ms. Spencer. This is for you.","TWN":"史賓瑟女士。請你接下電話。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_FLOOR_ADMIN_EMPLOYEE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당신 상급자를 불러도 마찬가지야. 그 기밀사항이란 걸 털어놓을 생각이 없다면…","JPN":"あなたの上司が出てきたって無駄よ。その機密事項を明かすつもりがないのなら……","ENG":"Call your boss all you want. If you're not willing to disclose your precious information–","TWN":"給你的上級打電話也是一樣。如果你們不想透露機密資訊……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"챔버의 시니어님입니다.","JPN":"チェンバーのシニアです。","ENG":"It's the Senior of Chamber.","TWN":"是強巴的Senior。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OPR_FLOOR_ADMIN_EMPLOYEE","text":{"KOREA":"원하는 질문에 답해주겠다고 하시네요.","JPN":"お求めの質問に答えられるそうです。","ENG":"He'll be answering any questions you might have.","TWN":"他說他會回答你任何問題。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"반갑습니다, 스펜서.","JPN":"はじめまして、スペンサーさん。","ENG":"Pleased to talk to you, Ms. Spencer.","TWN":"很高興認識你，史賓瑟。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"난 챔버의 관리자, 잭슨이라고 합니다.","JPN":"わたくしはチェンバーの管理者、ジャクソンと申します。","ENG":"I am Chamber's Administrator, Jackson.","TWN":"我叫傑森，強巴的管理者。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그래요, 잭슨 씨.","JPN":"はじめまして、ジャクソンさん。","ENG":"Yes. Mr. Jackson.","TWN":"你好，傑森先生。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"관리국의 시니어가 뭐가 아쉬워서 나한테 이런 의뢰를 하는 거죠?","JPN":"管理局のシニアともあろうお方が、どうしてこんな大仕事を私に任せようとするのですか？","ENG":"And why would a Senior of the Administration need the services of someone such as myself?","TWN":"管理局的Senior找我有什麼事嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"간단한 질문이군요.","JPN":"その質問の答えは明確です。","ENG":"That's a simple question to answer.","TWN":"很簡單。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"그건 당신이 심층으로 향하는 리프터들 중 가장 오래 살아남은 베테랑이기 때문입니다.","JPN":"それはあなたが深層部にダイブするリフターの中で、最も長く生き残つているベテランだからです。","ENG":"Because you're the most seasoned veteran among the lifters who've ventured into the abyss.","TWN":"因為你是現存最資深的打撈人。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"하지만 당신은 처음부터 날 찾지 않았어.","JPN":"だとしたら、初めから私に依頼していたはずだ。","ENG":"But I wasn't your first choice.","TWN":"但你一開始並未找過我。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나보다 먼저 5층으로 보낸 리프터가 얼마나 되지?","JPN":"私より先に依頼を受けて5階に向かったリフターはどのくらいいる？","ENG":"How many lifters did you send to the 5th floor before me?","TWN":"在我之前，你們派了多少打撈人去地下五層？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"지금까지 다섯 팀. 그들 모두 생환에 실패했습니다.","JPN":"これまでに5チーム。彼らは全員戻ってきませんでした。","ENG":"Five teams so far. None of them survived.","TWN":"目前為止有五支隊伍。他們都沒能活著回來。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"하지만 당신이 그곳까지 무사히 갈 수 있도록 길을 닦아두는 데엔 성공했죠.","JPN":"しかしあなたが目的地にたどり着きやすいよう、道を切り開くことに成功した。","ENG":"But they've succeeded in paving the way for you to get there.","TWN":"但我們成功地為你安全到達目的地鋪平了道路。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"처음부터 그럴 목적으로 사람들을 희생시킨 거라고?","JPN":"最初からそれを狙って、犠牲を出したってことか？","ENG":"That was your intention from the beginning? Sacrificing all those people just to make a path?","TWN":"從一開始你們就打算犧牲那些人嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"명색이 관리국인데, 그런 소릴 대놓고 해도 되나?","JPN":"管理局が、堂々とそんなことを話していいのか？","ENG":"I can't believe I just heard that coming from the Administration.","TWN":"管理局就是這樣肆無忌憚地做事的？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"챔버는 항상 기업의 진보적인 시도에 보탬이 되고자 사형수들을 실험 데이터로 제공해왔습니다.","JPN":"チェンバーは元より、企業の革新的な取り組みのために、死刑囚たちを実験データとして提供してきました。","ENG":"Chamber has always provided condemned prisoners as test data to support the progressive endeavors of corporations.","TWN":"強巴一直為公司提供死囚作為實驗資料，説明公司不斷進步。"},"stage":{"bg":"CHAMBER","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L28_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"성과를 위해 사회의 거름을 적극적으로 이용하는 게 챔버의 방식이니까요.","JPN":"成果を出すためなら、社会の肥しを積極的に活用する。それがチェンバーの持つ理念ですから。","ENG":"Utilizing societal outcasts for the betterment of society is the Chamber way.","TWN":"在我看來，強巴的做法是積極利用社會的肥料來取得成果。"},"stage":{"bg":"CHAMBER","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"기대를 망쳐서 미안한데, 나도 5층에 대해선 거의 몰라.","JPN":"水を差すようで悪いけど、私だって5階についてはほとんど情報を持っていない。","ENG":"Sorry to be a downer, but I don't know much about the 5th floor either.","TWN":"很抱歉辜負了你的期望，但我對地下五層知之甚少。"},"stage":{"bg":"CHAMBER","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당신이 말하는 목적지까지 무사히 가더라도, 탐사를 위해 위험을 감수하는 건 매한가지라고.","JPN":"あなたの言う目的地にたどり着くことができたとしても、探査に危険が伴うのに変わりはない。","ENG":"Even if I safely reach the destination, I'd still be sticking my neck out there.","TWN":"就算安全到達了你所說的目的地，探索所要冒的危險是一樣的。"},"stage":{"bg":"CHAMBER","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"이미 아케론 출신 징역수 중 가장 유능한 전투원들과 우리의 S급 카운터를 당신 팀에 편성해두었습니다.","JPN":"すでにアケロン出身の受刑者の中から優秀な戦闘員と、我々のSランクカウンターであなたのチームを編成しておきました。","ENG":"We've assigned the most skilled combatants among the inmates from Acheron and a Grade S Counter to your team.","TWN":"我們已經安排了實力最強的黃泉囚犯，以及一名S級制裁者加入你的隊伍。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JACKSON_CHAMBER_NULL_NULL","text":{"KOREA":"당신이 쉽게 죽게 내버려 두진 않을 겁니다.","JPN":"あなたを簡単に死なせるつもりはありません。","ENG":"We won't be leaving you to fend for yourself.","TWN":"我們不會讓你輕易死去的。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"정말로 관리국 시니어가 직접 그렇게 부탁했다고요?","JPN":"本当に管理局のシニアから、そんなことをお願いされたんですか？","ENG":"An Administration Senior went through that much trouble for you?","TWN":"管理局Senior真的這麼拜託你？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Yeah.","TWN":"嗯。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"스펜서 씨는 그걸 넙죽 수락했고요?","JPN":"それで、スペンサーさんはそれを承諾してしまったと？","ENG":"And you just accepted that?","TWN":"然後你就痛快地答應了？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"맞아.","JPN":"そうだ。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"수상할 정도로 아주 많은 보수를 나에게 제시했거든.","JPN":"不審に思うほどの多額の報酬を積まれたんだ。","ENG":"They offered me a suspiciously large amount of money.","TWN":"他們給了我一筆難以想像的高額報酬。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"목숨은요? 죽어버리면 돈이 다 무슨 소용인데요?","JPN":"命は？　死んでしまったらお金なんて意味ないじゃですか？","ENG":"What about your life? What good is money if you're dead?","TWN":"你的生命呢？如果你死了，要那麼多錢有什麼用？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나 죽거든 딴 일 알아봐.","JPN":"もし私が死んだら他の仕事をあたりな。","ENG":"If I die, then you go find yourself another job.","TWN":"等我死了，你就找點別的事去做吧。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"무, 무슨 그런 얘길 그렇게 가볍게 말합니까?!","JPN":"い、いったいどうしてそんなことを軽々しく言えるんですか！？","ENG":"W-why are you talking like it's not a big deal?!","TWN":"什麼，你為什麼說得這麼輕描淡寫？！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"하아… 컬킨.","JPN":"はあ……カルキン。","ENG":"*Sigh* Culkin.","TWN":"唉……克金。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"노파심에 하는 얘긴데, 나한테 관심가지면 너만 힘들어.","JPN":"これは忠告だけど、私に構うとあなたが辛くなるだけだ。","ENG":"I'm telling you this for your own good. It's your loss if you get attached to me.","TWN":"聽我一句勸，對我感興趣，你只會感到痛苦。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나 임자 있고 애도 딸린 여자라고.","JPN":"私は既婚者で、子どももいる。","ENG":"I'm a wife with a child.","TWN":"我是一個有丈夫和女兒的女人。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"…알고 있어요.","JPN":"……わかっています。","ENG":"...I know.","TWN":"……我知道。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"그 남편이란 사람은 불법이민자에 국가보안법을 어긴 중범죄자고, 멋대로 당신 딸을 데려간 뒤로는 5년째 연락 한 번 없었죠.","JPN":"でも、その夫という人は不法滞在者で、国家保安法に違反した重犯罪者。それにあなたの娘を連れ去って5年も姿をくらましている。","ENG":"But your husband is an illegal immigrant and a criminal who broke national security laws. And he's cut contact with you after taking your daughter away from you without a word five years ago.","TWN":"那個丈夫是非法移民，是違反國家安全法的重犯，自從他擅自帶走你的女兒以來，你已經五年沒有他的任何消息了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"당신은 그 사람을 찾기 위해 이면세계의 심부를 전전하다가 불치병까지 걸렸고요.","JPN":"あなたはその人を探しに裏世界の深部を彷徨い、あげくには不治の病にもなってしまった。","ENG":"You've been searching the depths of the Counterside for this man, even contracting a terminal illness in the process.","TWN":"你為了尋找那個人，徘徊在異界深處，最後卻染上了不治之症。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"컬킨, 그만.","JPN":"カルキン、もういい。","ENG":"Culkin. Stop.","TWN":"克金，別說了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"그런 인간 말종은 진작 잊어버리고 살았으면! 당신도 이렇게까지 비참한 삶을 살진…!","JPN":"そんなクズ野郎なんか！　とっくに忘れていれば、あなたがこんな悲惨な人生を生きることは……！","ENG":"If you just forgot about that worthless man and lived your own life, your life wouldn't be as miserable–!","TWN":"你要是趁早忘了那種人渣，也不至於像現在這樣過得那麼苦……！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"다 안다는 듯이 지껄이지 마.","JPN":"よく知りもしないくせに、わかったような口を利くな。","ENG":"Stop talking as if you know everything.","TWN":"別說得好像你什麼都知道一樣。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"죄송해요. 이런 얘긴 절대로 하면 안 되는 건데.","JPN":"すみません。言ってはいけないことだとわかっていながら、つい。","ENG":"I'm sorry. I never should have said that.","TWN":"……對不起。我不該說那樣的話。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"하아, 다 큰 자식이 뺨 한 대 맞았다고 울상은.","JPN":"はあ、大の男がちょっと叩かれたくらいでうるうるするなんて。","ENG":"You're a grown man. Stop crying over a sore cheek.","TWN":"那麼大的人了，挨一記耳光就哭喪著臉。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"다 널 위한 거야. 나 대신 젊고 건강한 여자 만나 행복하게 살다 보면, 내가 걷어찬 일을 두고두고 고마워하게 될 걸?","JPN":"これは、あなたのために言ってるんだ。私じゃなくてもっと若くて健康な女性と結ばれて、幸せに暮らしていれば、私に振られたことを感謝するようになるさ。","ENG":"This is all for you. Once you meet a younger, prettier girl, you'll eventually be thankful I left you in the dust.","TWN":"這都是為你好。你遲早能遇到一個年輕、健康的女孩，從此過上幸福的生活。到時候，你一定會感激我所做的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나한테 붙어있어봐야 얻는 건 병수발 밖에 없다고.","JPN":"私の側にいたところで、この先私を看病する未来が待っているだけ。","ENG":"You'll only end up with a patient to look after if you stick around with me.","TWN":"跟著我，你最後會被拖累的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"스펜서 씨…","JPN":"スペンサーさん……","ENG":"Ms. Spencer...","TWN":"史賓瑟……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"지난 5년 동안 날 도와주느라 고생 많았어, 컬킨.","JPN":"今まで5年間、私をサポートしてくれてありがとう。カルキン。","ENG":"You've been through a lot helping me out over the past five years, Culkin.","TWN":"克金，過去五年裡你給了我很多幫助，我很感激。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"챔버 근로보장법 기준에 맞춰서 퇴직금은 넉넉히 챙겨줄게.","JPN":"チェンバーの勤労基準法を元に退職金は十分に渡すようにする。","ENG":"I'll make sure to send you off with a generous severance package in accordance with Chamber's labor protection laws.","TWN":"根據強巴勞基法的標準，我會給你準備一筆豐厚的遣散費。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"기회를 한 번만 더 주실 순 없겠죠?","JPN":"もう一度チャンスをいただけませんか？","ENG":"Would giving me another chance be out of the question, now?","TWN":"……這麼說，我已經沒有機會了嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"네가 한 짓이 꼴불견인 건 인정하는데, 그것 때문은 아니야.","JPN":"あなたの態度はみっともなかったけど、そういうことじゃないんだ。","ENG":"What you did was pathetic, but that's not just why.","TWN":"我承認你現在的樣子有點難看，但不是這個原因。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아무래도, 이번 의뢰를 끝으로 리프터 일은 이제 관둘 것 같아서.","JPN":"私は今回の依頼を最後に、リフター業を引退しようと思っている。","ENG":"I think I'll quit being a lifter after this job.","TWN":"不管怎樣，我打算完成這次委託後就辭掉打撈人的工作。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"네…? 그게 정말인가요?","JPN":"え……？　それは本当ですか？","ENG":"What...? Do you mean that?","TWN":"什麼……？你認真的？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"관리국이 북방합의체 산하 연구조직을 쫓고 있다는 말을 했어.","JPN":"管理局が北方合意体傘下の研究組織を追っていると聞いた。","ENG":"The Administration mentioned that they were chasing after a research organization under the Northern Union.","TWN":"管理局說他們正在追捕北方和議會下屬的一個研究組織，這個組織所研究的專案可能會對全人類安全構成威脅。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"인류안위에 위협이 되는 프로젝트의 핵심고문 한 명을 찾았는데, 대균열 심층에 들어가는 걸 목격하고 돌아오길 기다렸지만 3개월째 무소식이래.","JPN":"人類の平和を脅かす、そのプロジェクトの主要人物の一人を特定できたけど、大亀裂の深層部に入るのを目撃されたきり、3カ月も音沙汰がないそうだ。","ENG":"They found one of the key consultants to a project that pose a threat to humanity. They've been waiting for that person to return after witnessing him enter the depths of the Grand Dimension Crevice, but it's been three months with no news since then.","TWN":"他們找到了其中的一個關鍵顧問，並且目擊他進入了大峽谷深處。但三個月過去了，都沒有他回來的消息。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"역시… 의뢰를 수락한 건 그것 때문이었군요.","JPN":"やっぱり……依頼を許諾したのは、それが理由だったんですね。","ENG":"So... that's why you accepted the request.","TWN":"果然……這才是你接受這個委託的原因。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"하지만 말도 안 돼요. 3개월이 지나도 살아 돌아오지 못했다면 죽었다는 거잖아요.","JPN":"でも、だとしたらおかしいです。3カ月も戻らないということは、死亡したも同然ですよね。","ENG":"But that can't be right. If this person hasn't returned in three months, then he must be dead.","TWN":"但這有什麼意義？如果這個人超過三個月都沒有回來，那就說明他已經死了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아무래도 관리국은 살아있다고 생각하는 것 같아.","JPN":"どうやら、管理局は生存していると踏んでいるようだ。","ENG":"It seems the Administration believes he's still alive.","TWN":"管理局認為他還活著。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나한테 보수로 제시한 천문학적인 액수의 크레딧은 그 추측이 가볍지 않다는 반증이고.","JPN":"私に提示された天文学的な報酬額をみるからに、きっと相当固い確信があるに違いない。","ENG":"The ludicrous amount of credit they offered makes me think they have a good reason to believe that.","TWN":"從他們向我提供的天價報酬來看，就足以證明這個推測很有可能是正確的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그래서, 내 눈으로 직접 확인해보려고 해.","JPN":"だから、この目で直接確かめる。","ENG":"So, I want to see for myself with my own eyes.","TWN":"所以，我想要親眼確認下。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 남자가 살아있긴 한건지.","JPN":"その男が、生きているのかどうか。","ENG":"Whether that man is truly alive or not.","TWN":"那個男人是否還活著。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"살아 있다면 거기서 대체 뭘 하고 있는지.","JPN":"もし生きているのなら、いったいあんな場所で何をしているのか。","ENG":"And what he's been doing down there if he is.","TWN":"如果他還活著，到底會在那做什麼？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"혼자 가시는 건 아니죠?","JPN":"まさか一人で行かれるんじゃないですよね？","ENG":"You're not going alone, are you?","TWN":"你不是一個人去吧？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이런 일에 제정신으로 지원할 사람이 없다는 건 그쪽에서도 알고 있어.","JPN":"まともな人間がこんな仕事を受けるわけがないのは、向こうもわかっている。","ENG":"Even the Administration knew nobody in their right mind would accept a job like this.","TWN":"他們也知道只要腦子還正常的人就不會接受這種委託。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"챔버의 사형수들 중 가장 쓸모 있는 전문인력을 선별해서 붙여준대.","JPN":"チェンバーの死刑囚の中から最も優秀な人材を選抜して帯同させてくれるみたいだ。","ENG":"They said they'll select and appoint the most useful prisoners among Chamber's death row inmates.","TWN":"說是會從死囚裡挑選最有用的專業人員。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"중범죄자들을 함께 보낸다고요?! 관리국이 그렇게 무책임해도 되는 겁니까?","JPN":"凶悪犯罪者とですか？　そんな無責任なやり方、管理局がしていいはずがない。","ENG":"You'll be going down there with convicts?! Can the Administration be any more irresponsible?","TWN":"讓你和死囚犯一起下去？！管理局還能再不負責任一點嗎！？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"차라리 제가 갈게요! 실전경험은 없어도 어깨너머로 배운 게 있으니 어느 정도 도움은…!","JPN":"でしたら私がついていきます！　現場での経験はありませんが、これでもスペンサーさんの背中を見て学んできたつもりなので、ある程度はお役に……！","ENG":"I'll come go with you! Even though I don't have practical experience, I've learned enough over the years to be of some help...!","TWN":"還不如我和你去！即使我沒有實踐經驗，但也學了些東西，可以提供一點幫助……！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"고난도 작업에 초짜가 섞이면 너 챙기다 나까지 위험해질 거야. 그러길 원해?","JPN":"これは難易度の高い仕事だ。あなたみたいな素人が混じってたら、フォローする私まで危険にさらされる。それでもいいのか？","ENG":"Taking care of a novice during a high-risk operation is going to make this that much harder for me. Is that what you want?","TWN":"在這種高難度的任務中還要讓我分心照顧新手。你確定嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"윽… 아뇨.","JPN":"くっ……いいえ。","ENG":"Ugh... No.","TWN":"呃……算了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그리고 죄수들만 있는 건 아니야. 관리국에서 고용한 S급 카운터 에이전트도 한 명 붙여준다고 했으니까.","JPN":"それに、犯罪者だけではない。管理局が抱えるS級カウンターも一人参加する。","ENG":"And it won't just be convicts. The Administration also mentioned a Grade S Counter agent.","TWN":"不僅僅是囚犯。他們還會派出一名管理局聘請的S級制裁者。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"S급이요? 그건 잘 됐네요.","JPN":"S級ですか？　それならよかった。","ENG":"Grade S? That's good news.","TWN":"S級？那還不錯。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASSIST_FLOOR_NPC_CULKIN","text":{"KOREA":"게다가 관리국에서 일을 맡기는 카운터라면, 분명 믿을 수 있는 듬직한 사람일 테니까요.","JPN":"管理局が仕事を頼むカウンターなら、きっと信頼できる実力の持ち主に違いありません。","ENG":"If it's a Counter trusted by the Administration, then this person must be trustworthy and reliable.","TWN":"既然是受雇於管理局的制裁者，一定是個值得信賴、可靠的人。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASSIST_FLOOR_NPC_CULKIN","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_QM","text":{"KOREA":"안녕하세요! 잘 부탁드립니다!","JPN":"こんにちは！　よろしくお願いいたします！","ENG":"Hello! Nice to meet you!","TWN":"你好！請多多關照！"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_QM","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"방금 나한테 인사한 거야?","JPN":"今のは私に言ったのか？","ENG":"You saying hi to me?","TWN":"你剛才跟我打招呼了嗎？"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_QM","text":{"KOREA":"네! 보고 싶었어요! 스펜서!","JPN":"はい！　お会いしたいと思っていました！　スペンサーさん！","ENG":"Yes! I wanted to see you, Spencer!","TWN":"沒錯！我很想見見你！史賓瑟！"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_QM","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그쪽이 S급 에이전트?","JPN":"あなたが、S級エージェント？","ENG":"You're the Grade S agent?","TWN":"你就是那個S級制裁者？"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_QM","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"네! 힉스라고 불러주세요! 제 코드네임이에요!","JPN":"はい！　ヒックスとお呼びください！　私のコードネームですので！","ENG":"Yes! Call me Hicks! That's my codename!","TWN":"嗯！請叫我希克斯！這是我的代號！"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"힉스, 본인이 어떤 일에 지원한 건지 알고 있지?","JPN":"ヒックス、自分が志願した仕事について理解しているか？","ENG":"Hicks, do you know what you signed up for?","TWN":"希克斯，你知道你申請的是什麼工作嗎？"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"초고심도를 탐사하는 엄청 위험한 일이요!","JPN":"超高深度部の探査という大変危険な仕事です！","ENG":"A super dangerous mission exploring the hyperdepths!","TWN":"探索超深度異界，一項非常危險的工作！"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"침식체의 습격에 목을 뜯기거나, 움직이는 돌에 다리가 짓이겨지고, 침식성 포자에 뒤덮여 내장이 뒤집히는 고통과 함께 피를 토하거나, 중성자 차원폭풍에 휘말려 살점이 녹아버리는…!","JPN":"侵食体に襲われ首を噛み千切られたり、動き回る石に脚を潰されてたり、侵食性の胞子に覆われて内臓が締め上げられるような苦痛とともに吐血したり、中性子性次元爆風に巻き込まれ皮膚が溶けてしまうような……！","ENG":"Being torn apart by the jaws of a C.O., crushed by moving rocks, hurling blood as your organs get twisted by Corrupted spores, or even getting my flesh melted off in a dimensional neutron storm...!","TWN":"被侵蝕體扯斷脖子；被落石壓碎腿骨；被侵蝕孢子覆蓋全身，在內臟劇痛中吐血而亡；被捲入中子風暴中，身體瞬間融化……！"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"뭐… 그런 일은 되도록 피하려고 하는 편이긴 한데, 틀린 얘긴 없네.","JPN":"まあ……そういうことにはならないように気をつけたいところではあるんだけれど、その通りよ。","ENG":"Well... We're trying to avoid such things, but you're not wrong.","TWN":"唔……我會盡可能避免類似的事情，但你說得沒錯。"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"스펜서는 그런 위험천만한 모험을 하는 분이라면서요?","JPN":"スペンサーさんは、そういう危険な冒険をしている方ですよね！","ENG":"I heard you're someone who embarks on such perilous adventures. Is that right, Spencer?","TWN":"我聽說史賓瑟是一個勇於冒險的人？"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"저도 엄청 좋아해요. 그런 거!","JPN":"私も大好きなんです！　そういうの！","ENG":"I love it too! Danger!","TWN":"我也很喜歡冒險。比如剛剛說的那些！"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"관리국에서 하던 일반적인 다이브와는 다를 거야.","JPN":"管理局が行っている、一般的なダイブとは様相が異なるはずだ。","ENG":"This will be a tad different from the typical dive the Administration makes you do.","TWN":"這次的躍入不同於尋常的管理局躍入。"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이쪽은 차원함선 대신 대균열을 직접 뚫고 들어가는 승강기를 사용하니까.","JPN":"私たちは次元艦船は使わず、大亀裂に直接穴を掘って潜っていく昇降機を使うから。","ENG":"In this case, we'll be using elevators to get through the Grand Dimension Crevice instead of a dimensional ship.","TWN":"這次不會使用次元艦船，而是使用升降機，直接深入大峽谷。"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"작업환경이 열악하고, 사고위험도 높지.","JPN":"作業環境は劣悪で、事故率も高い。","ENG":"Terrible working conditions and high risk of accidents.","TWN":"工作環境惡劣，且事故風險高。"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"괜찮아요. 저는 스펜서를 지키기 위해 온 거니까요.","JPN":"大丈夫ですよ。私はスペンサーさんをお守りするために来たんですから。","ENG":"That's fine. I'm just here to protect you, Spencer.","TWN":"沒關係。因為我是來保護史賓瑟的。"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"그러니 마음껏 부려먹으세요!","JPN":"ですから、いくらでもこき使ってください！","ENG":"So put me to work!","TWN":"所以，盡情使喚我吧！"},"stage":{"bg":"WAREHOUSE_03","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"힉스, 선발대가 실종된 장소를 알 수 있다고 했지?","JPN":"ヒックス、先発隊が行方不明になった場所を調べられるな？","ENG":"Hicks, you said you know where the advance party went missing, right?","TWN":"好，希克斯，你說你能找到先遣隊的失蹤地點，對嗎？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"네! 제가 냄새는 기가 막히게 잘 맡거든요!","JPN":"はい！　私は匂いを嗅ぎあてるのが超得意なんです！","ENG":"Yes! I have an excellent sense of smell!","TWN":"嗯！我的嗅覺非常靈敏！"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그럼 단독정찰. 맡길게.","JPN":"じゃあ単独偵察を頼む。","ENG":"Then I'll leave the scouting to you.","TWN":"那麼，偵察的任務就交給你了。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};